mapper.select:
select id, agent_id as agentId, session_name as sessionName, last_message_at as lastMessageAt, create_time as createTime, update_time as updateTime, status, reserve, remark, model_id as modelId, client_id as clientId from agent_chat_session where agent_id = #{agentId}
and model_id = #{modelId}
and client_id = #{clientId}
order by last_message_at desc limit 100
